form:Form.form:Scripts:
		function set_f_hasta(me){
	var date = AddDays(me.TypedValue(), 30);  	
 	Ctrl('f_hasta').SetXValue(date2str(date)); 
}
function Filtrar()
{               
    if (arrFILTER.length == 0)
    {             
        alert("No hay legajos filtrados.");
        return false;
    } 

    if (arrFILTER.length > 200)
    {             
        alert("Hay demasiados registros seleccionados, afine la búsqueda.");
        return false;
    }

    FillArray(100);

    Ctrl("main").DoEvent("FILTER");

}
